import React, { useState, useEffect } from 'react';
import {
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  CardActions,
  Button,
  Box,
  CircularProgress,
  Alert
} from '@mui/material';
import { api } from '../services/api';

const Certificates = ({ featured = false }) => {
  const [certificates, setCertificates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCertificates = async () => {
      try {
        const response = await api.get(`/certificates${featured ? '?featured=true' : ''}`);
        setCertificates(response.data);
        setLoading(false);
      } catch (err) {
        setError('Failed to fetch certificates');
        setLoading(false);
      }
    };

    fetchCertificates();
  }, [featured]);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" my={4}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  return (
    <Grid container spacing={4}>
      {certificates.map((certificate) => (
        <Grid item key={certificate._id} xs={12} sm={6} md={4}>
          <Card
            sx={{
              height: '100%',
              display: 'flex',
              flexDirection: 'column'
            }}
          >
            <CardMedia
              component="img"
              height="200"
              image={certificate.imageUrl || 'https://source.unsplash.com/random?certificate'}
              alt={certificate.title}
            />
            <CardContent sx={{ flexGrow: 1 }}>
              <Typography gutterBottom variant="h5" component="h2">
                {certificate.title}
              </Typography>
              <Typography variant="subtitle1" color="text.secondary" gutterBottom>
                {certificate.issuer}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Issued: {new Date(certificate.issueDate).toLocaleDateString()}
              </Typography>
              {certificate.expiryDate && (
                <Typography variant="body2" color="text.secondary">
                  Expires: {new Date(certificate.expiryDate).toLocaleDateString()}
                </Typography>
              )}
              <Typography variant="body1" sx={{ mt: 2 }}>
                {certificate.description}
              </Typography>
            </CardContent>
            <CardActions>
              {certificate.credentialUrl && (
                <Button
                  size="small"
                  color="primary"
                  href={certificate.credentialUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  View Credential
                </Button>
              )}
            </CardActions>
          </Card>
        </Grid>
      ))}
    </Grid>
  );
};

export default Certificates;
